// Dense layer 0  in=16  out=1
static const float den0_w[1][16] = {
    {-0.11646026f, 0.11635379f, -0.24509969f, -0.30574581f, -0.11799517f, 0.22569656f, 0.00821404f, -0.38220954f, -0.18974532f, -0.29997739f, -0.12333870f, -0.08708216f, -0.23342080f, -0.17073192f, -0.11770377f, -0.03824563f}
};
static const float den0_b[] = {0.14372781f};

class LNNModel {
public:
    float predict(float* input, int seq_len);

    // Reset hidden states (Call this before predicting a new sequence!)
    void reset_states() {
        for(int k=0; k<32; k++) h0[k] = 0.0f;
        for(int k=0; k<16; k++) h1[k] = 0.0f;
    }

private:
    float h0[32] = {0};
    float h0_new[32];
    float h1[16] = {0};
    float h1_new[16];
};

float LNNModel::predict(float* input, int seq_len) {
    const int INPUT_SIZE = 1;
    float dense_in[16];
    float dense_out[16];
    float x_t_buf[INPUT_SIZE];
    float* x_t = x_t_buf;

    for (int t = 0; t < seq_len; t++) {
        x_t = x_t_buf; // <--- CORREÇÃO CRÍTICA: Reseta o ponteiro no início do time step
        for (int k = 0; k < INPUT_SIZE; k++)
            x_t_buf[k] = input[t * INPUT_SIZE + k];

        // ---- LTC layer 0  ode_unfolds=6  delta=0.166667 ----
        for (int u = 0; u < 6; u++) {
            // -- backbone f(W_ih·x + W_hh·h + b) --
            float f_val[32];
            for (int k = 0; k < 32; k++) {
                float acc = rec0_W_ih_b[k];
                for (int j = 0; j < 1; j++)
                    acc += rec0_W_ih_w[k][j] * x_t[j];
                float hacc = rec0_W_hh_b[k];
                for (int j = 0; j < 32; j++)
                    hacc += rec0_W_hh_w[k][j] * h0[j];
                float pre = acc + hacc;
                pre = tanhf(pre);
                f_val[k] = pre;
            }
            // -- time constant τ = tau_min + softplus(A * sigmoid(W_tau·x + W_tauh·h)) --
            for (int k = 0; k < 32; k++) {
                float g = rec0_W_tau_b[k];
                for (int j = 0; j < 1; j++)
                    g += rec0_W_tau_w[k][j] * x_t[j];
                for (int j = 0; j < 32; j++)
                    g += rec0_W_tauh_w[k][j] * h0[j];
                float gate = 1.0f / (1.0f + expf(-g));
                float ag   = rec0_A[k] * gate;
                // softplus with overflow guard
                float sp   = ag < 88.0f ? logf(1.0f + expf(ag)) : ag;
                float tau  = 0.050000f + sp;
                // Euler step: h += delta * (-h + f) / tau
                h0_new[k] = h0[k] + 0.16666667f * (-h0[k] + f_val[k]) / tau;
            }
            for (int k = 0; k < 32; k++) h0[k] = h0_new[k];
        }
        x_t = h0;

        // ---- LTC layer 1  ode_unfolds=4  delta=0.250000 ----
        for (int u = 0; u < 4; u++) {
            // -- backbone f(W_ih·x + W_hh·h + b) --
            float f_val[16];
            for (int k = 0; k < 16; k++) {
                float acc = rec1_W_ih_b[k];
                for (int j = 0; j < 32; j++)
                    acc += rec1_W_ih_w[k][j] * x_t[j];
                float hacc = rec1_W_hh_b[k];
                for (int j = 0; j < 16; j++)
                    hacc += rec1_W_hh_w[k][j] * h1[j];
                float pre = acc + hacc;
                pre = tanhf(pre);
                f_val[k] = pre;
            }
            // -- time constant τ = tau_min + softplus(A * sigmoid(W_tau·x + W_tauh·h)) --
            for (int k = 0; k < 16; k++) {
                float g = rec1_W_tau_b[k];
                for (int j = 0; j < 32; j++)
                    g += rec1_W_tau_w[k][j] * x_t[j];
                for (int j = 0; j < 16; j++)
                    g += rec1_W_tauh_w[k][j] * h1[j];
                float gate = 1.0f / (1.0f + expf(-g));
                float ag   = rec1_A[k] * gate;
                // softplus with overflow guard
                float sp   = ag < 88.0f ? logf(1.0f + expf(ag)) : ag;
                float tau  = 0.100000f + sp;
                // Euler step: h += delta * (-h + f) / tau
                h1_new[k] = h1[k] + 0.25000000f * (-h1[k] + f_val[k]) / tau;
            }
            for (int k = 0; k < 16; k++) h1[k] = h1_new[k];
        }
        x_t = h1;

    } // end time-step loop

    // ---- Dense head ----
    // Dense 0  in=16  out=1  act=linear
    for (int k = 0; k < 1; k++) {
        float acc = den0_b[k];
        for (int j = 0; j < 16; j++)
            acc += den0_w[k][j] * h1[j];
        dense_out[k] = acc;
    }

    return dense_out[0];
}